import React from "react";
import { interpolate, spring, useCurrentFrame, useVideoConfig } from "remotion";

/**
 * Headline variations cycle through different entrance animations
 * to keep the video visually interesting across 27+ segments.
 */

const HEADLINE_VARIANTS = [
  "slide-up",
  "fade-scale",
  "slide-left",
  "typewriter",
] as const;

type HeadlineVariant = (typeof HEADLINE_VARIANTS)[number];

export const Headline: React.FC<{
  text: string;
  segmentIndex: number;
  durationFrames: number;
  type?: "full" | "insight" | "atomic";
}> = ({ text, segmentIndex, durationFrames, type = "full" }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const variant: HeadlineVariant =
    HEADLINE_VARIANTS[segmentIndex % HEADLINE_VARIANTS.length];

  const fontSize = type === "atomic" ? 110 : 72;
  const padding = type === "atomic" ? "0 40px" : "0 120px";

  const currentStyle = {
    ...baseStyle,
    fontSize,
    padding,
  };

  // Entrance spring (delay 5 frames)
  const entranceSpring = spring({
    frame: frame - 5,
    fps,
    config: { damping: 14, mass: 0.8 },
  });

  // Exit fade (last 15 frames of segment)
  const exitOpacity = interpolate(
    frame,
    [durationFrames - 15, durationFrames],
    [1, 0],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" },
  );

  // Calculate variant-specific styles
  let variantStyle: React.CSSProperties = {};

  switch (variant) {
    case "slide-up":
      variantStyle = {
        transform: `translateY(${interpolate(entranceSpring, [0, 1], [60, 0])}px)`,
        opacity: entranceSpring * exitOpacity,
      };
      break;

    case "fade-scale":
      variantStyle = {
        transform: `scale(${interpolate(entranceSpring, [0, 1], [0.7, 1])})`,
        opacity: entranceSpring * exitOpacity,
      };
      break;

    case "slide-left":
      variantStyle = {
        transform: `translateX(${interpolate(entranceSpring, [0, 1], [80, 0])}px)`,
        opacity: entranceSpring * exitOpacity,
      };
      break;

    case "typewriter": {
      const charsToShow = Math.floor(
        interpolate(frame, [5, 5 + text.length * 1.5], [0, text.length], {
          extrapolateLeft: "clamp",
          extrapolateRight: "clamp",
        }),
      );
      variantStyle = {
        opacity: exitOpacity,
      };
      // Override the text content via a different approach below
      return (
        <div style={{ ...currentStyle, ...variantStyle }}>
          {text.slice(0, charsToShow)}
          {charsToShow < text.length && (
            <span
              style={{
                borderRight:
                  frame % 15 < 8
                    ? `3px solid #4facfe`
                    : "3px solid transparent",
                marginLeft: 2,
                boxShadow: frame % 15 < 8 ? "0 0 8px #4facfe" : "none",
              }}
            />
          )}
        </div>
      );
    }
  }

  return <div style={{ ...currentStyle, ...variantStyle }}>{text}</div>;
};

const baseStyle: React.CSSProperties = {
  fontFamily: "Inter, sans-serif",
  fontSize: 72,
  fontWeight: 900,
  color: "white",
  textAlign: "center",
  textShadow: [
    "0 2px 0 rgba(0,0,0,0.95)",
    "0 6px 24px rgba(0,0,0,0.85)",
    "0 0 60px rgba(79,172,254,0.55)",
    "0 0 120px rgba(79,172,254,0.25)",
  ].join(", "),
  WebkitTextStroke: "1.5px rgba(0,0,0,0.7)",
  lineHeight: 1.15,
  padding: "0 120px",
  letterSpacing: -1,
};
